// packages/cli/src/ui/utils/historyExportUtils.ts
import * as fsPromises from "node:fs/promises";
import path23 from "node:path";
function serializeHistoryToMarkdown(history) {
  return history.map((item) => {
    const text = item.parts?.map((part) => {
      if (part.text) {
        return part.text;
      }
      if (part.functionCall) {
        return `**Tool Command**:
\`\`\`json
` + JSON.stringify(part.functionCall, null, 2) + "\n```";
      }
      if (part.functionResponse) {
        return `**Tool Response**:
\`\`\`json
` + JSON.stringify(part.functionResponse, null, 2) + "\n```";
      }
      return "";
    }).join("") || "";
    const roleIcon = item.role === "user" ? "\u{1F9D1}\u200D\u{1F4BB}" : "\u2728";
    return `## ${(item.role || "model").toUpperCase()} ${roleIcon}

${text}`;
  }).join("\n\n---\n\n");
}
async function exportHistoryToFile(options) {
  const { history, filePath } = options;
  const extension = path23.extname(filePath).toLowerCase();
  let content;
  if (extension === ".json") {
    content = JSON.stringify(history, null, 2);
  } else if (extension === ".md") {
    content = serializeHistoryToMarkdown(history);
  } else {
    throw new Error(
      `Unsupported file extension: ${extension}. Use .json or .md.`
    );
  }
  const dir = path23.dirname(filePath);
  await fsPromises.mkdir(dir, { recursive: true });
  await fsPromises.writeFile(filePath, content, "utf-8");
}

