async function updateGitignore(gitRepoRoot) {
  const gitignoreEntries = [".gemini/", "gha-creds-*.json"];
  const gitignorePath = path36.join(gitRepoRoot, ".gitignore");
  try {
    let existingContent = "";
    let fileExists2 = true;
    try {
      existingContent = await fs37.promises.readFile(gitignorePath, "utf8");
    } catch {
      fileExists2 = false;
    }
    if (!fileExists2) {
      const contentToWrite = gitignoreEntries.join("\n") + "\n";
      await fs37.promises.writeFile(gitignorePath, contentToWrite);
    } else {
      const missingEntries = gitignoreEntries.filter(
        (entry) => !existingContent.split(/\r?\n/).some((line) => line.split("#")[0].trim() === entry)
      );
      if (missingEntries.length > 0) {
        const contentToAdd = "\n" + missingEntries.join("\n") + "\n";
        await fs37.promises.appendFile(gitignorePath, contentToAdd);
      }
    }
  } catch (error) {
    debugLogger.debug("Failed to update .gitignore:", error);
  }
}
async function downloadFiles({
  paths,
  releaseTag,
  targetDir,
  proxy,
  abortController
}) {
  const downloads = [];
  for (const fileBasename of paths) {
    downloads.push(
      (async () => {
        const endpoint = `${REPO_DOWNLOAD_URL}/refs/tags/${releaseTag}/${SOURCE_DIR}/${fileBasename}`;
        const response = await fetch(endpoint, {
          method: "GET",
          dispatcher: proxy ? new import_undici2.ProxyAgent(proxy) : void 0,
          signal: AbortSignal.any([
            AbortSignal.timeout(3e4),
            abortController.signal
          ])
        });
        if (!response.ok) {
          throw new Error(
            `Invalid response code downloading ${endpoint}: ${response.status} - ${response.statusText}`
          );
        }
        const body = response.body;
        if (!body) {
          throw new Error(
            `Empty body while downloading ${endpoint}: ${response.status} - ${response.statusText}`
          );
        }
        const destination = path36.resolve(
          targetDir,
          path36.basename(fileBasename)
        );
        const fileStream = fs37.createWriteStream(destination, {
          mode: 420,
          // -rw-r--r--, user(rw), group(r), other(r)
          flags: "w",
          // write and overwrite
          flush: true
        });
        await body.pipeTo(Writable.toWeb(fileStream));
      })()
    );
  }
  await Promise.all(downloads).finally(() => {
    abortController.abort();
  });
}
async function createDirectory(dirPath) {
  try {
    await fs37.promises.mkdir(dirPath, { recursive: true });
  } catch (error) {
    debugLogger.debug(`Failed to create ${dirPath} directory:`, error);
    throw new Error(
      `Unable to create ${dirPath} directory. Do you have file permissions in the current directory?`
    );
  }
}
async function downloadSetupFiles({
  configs,
  releaseTag,
  proxy
}) {
  try {
    await Promise.all(
      configs.map(({ paths, targetDir }) => {
        const abortController = new AbortController();
        return downloadFiles({
          paths,
          releaseTag,
          targetDir,
          proxy,
          abortController
        });
      })
    );
  } catch (error) {
    debugLogger.debug("Failed to download required setup files: ", error);
    throw error;
  }
}
var setupGithubCommand = {
  name: "setup-github",
  description: "Set up GitHub Actions",
  kind: "built-in" /* BUILT_IN */,
  autoExecute: true,
  action: async (context) => {
    if (!isGitHubRepository()) {
      throw new Error(
        "Unable to determine the GitHub repository. /setup-github must be run from a git repository."
      );
    }
    let gitRepoRoot;
    try {
      gitRepoRoot = getGitRepoRoot();
    } catch (error) {
      debugLogger.debug(`Failed to get git repo root:`, error);
      throw new Error(
        "Unable to determine the GitHub repository. /setup-github must be run from a git repository."
      );
    }
    const proxy = context?.services?.agentContext?.config.getProxy();
    const releaseTag = await getLatestGitHubRelease(proxy);
    const readmeUrl = `https://github.com/google-github-actions/run-gemini-cli/blob/${releaseTag}/README.md#quick-start`;
    const workflowsDir = path36.join(gitRepoRoot, ".github", "workflows");
    await createDirectory(workflowsDir);
    const commandsDir = path36.join(gitRepoRoot, ".github", "commands");
    await createDirectory(commandsDir);
    await downloadSetupFiles({
      configs: [
        { paths: GITHUB_WORKFLOW_PATHS, targetDir: workflowsDir },
        { paths: GITHUB_COMMANDS_PATHS, targetDir: commandsDir }
      ],
      releaseTag,
      proxy
    });
    await updateGitignore(gitRepoRoot);
    const commands = [];
    if (process.platform !== "win32") {
      commands.push("set -eEuo pipefail");
    }
    commands.push(
      `echo "Successfully downloaded ${GITHUB_WORKFLOW_PATHS.length} workflows , ${GITHUB_COMMANDS_PATHS.length} commands and updated .gitignore. Follow the steps in ${readmeUrl} (skipping the /setup-github step) to complete setup."`
    );
    commands.push(...getOpenUrlsCommands(readmeUrl));
    const command = `(${commands.join(" && ")})`;
    return {
      type: "tool",
      toolName: "run_shell_command",
      toolArgs: {
        description: "Setting up GitHub Actions to triage issues and review PRs with Gemini.",
        command
      }
    };
  }
};

